package com.veetu.vadagai.auth;import com.veetu.vadagai.auth.AuthDtos.*;import com.veetu.vadagai.user.*;import lombok.RequiredArgsConstructor;import org.springframework.beans.factory.annotation.Value;import org.springframework.security.authentication.*;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;
@Service @RequiredArgsConstructor public class AuthService{private final UserRepository users;private final RefreshTokenRepository refreshTokens;private final PasswordEncoder encoder;private final AuthenticationManager auth;private final JwtService jwt;@Value("${security.jwt.refresh-token-days}") long refreshDays;@Transactional public TokenResponse register(RegisterRequest r){if(users.existsByEmailIgnoreCase(r.email()))throw new IllegalArgumentException("Email already registered");var u=User.builder().email(r.email().toLowerCase()).passwordHash(encoder.encode(r.password())).fullName(r.fullName()).mobile(r.mobile()).roles(Set.of(r.role())).emailVerified(true).build();users.save(u);return tokens(u);}@Transactional public TokenResponse login(LoginRequest r){auth.authenticate(new UsernamePasswordAuthenticationToken(r.email(),r.password()));var u=users.findByEmailIgnoreCaseAndDeletedFalse(r.email()).orElseThrow();return tokens(u);}@Transactional public TokenResponse refresh(RefreshRequest r){var rt=refreshTokens.findByTokenAndRevokedFalse(r.refreshToken()).filter(t->t.getExpiresAt().isAfter(Instant.now())).orElseThrow(()->new IllegalArgumentException("Invalid refresh token"));return tokens(rt.getUser());}@Transactional public void forgot(ForgotPasswordRequest r){users.findByEmailIgnoreCaseAndDeletedFalse(r.email()).ifPresent(u->{u.setOtpHash(encoder.encode("123456"));u.setOtpExpiresAt(Instant.now().plus(Duration.ofMinutes(10)));});}@Transactional public void reset(ResetPasswordRequest r){var u=users.findByEmailIgnoreCaseAndDeletedFalse(r.email()).orElseThrow(()->new IllegalArgumentException("Invalid OTP"));if(u.getOtpExpiresAt()==null||u.getOtpExpiresAt().isBefore(Instant.now())||!encoder.matches(r.otp(),u.getOtpHash()))throw new IllegalArgumentException("Invalid OTP");u.setPasswordHash(encoder.encode(r.newPassword()));u.setOtpHash(null);u.setOtpExpiresAt(null);}private TokenResponse tokens(User u){String refresh=UUID.randomUUID()+"."+UUID.randomUUID();refreshTokens.save(RefreshToken.builder().user(u).token(refresh).expiresAt(Instant.now().plus(Duration.ofDays(refreshDays))).build());return new TokenResponse(jwt.create(u),refresh,"Bearer",u.getRoles(),u.getFullName());}}
